result:
:root {
  color-scheme: dark;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
  margin: 0;
  padding: 0;
  background: #0b1020;
  color: #ddd;
  overflow: hidden;
}

canvas {
  display: block;
  width: 100vw;
  height: 100vh;
  background: transparent;
  margin: 0;
  padding: 0;
  touch-action: none;
}
